queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?cuisine_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCuisines ?child ; p:hasFood_Critics ?parent . } GROUP BY ?child }
  ?child p:cuisine_name ?cuisine_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Food_Critics } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?critic_name ?cuisine_name WHERE {
  ?food_critics_cuisines a :Food_Critics_Cuisines .
  ?cuisines a :Cuisines .
  ?food_critics_cuisines p:hasCuisines ?cuisines .
  ?food_critics a :Food_Critics .
  ?food_critics_cuisines p:hasFood_Critics ?food_critics .
  ?food_critics p:critic_name ?critic_name .
  ?cuisines p:cuisine_name ?cuisine_name .
} }
  collective: { SELECT ?cuisine_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCuisines ?child ; p:hasFood_Critics ?parent . } GROUP BY ?child }
  ?child p:cuisine_name ?cuisine_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Food_Critics } }
  FILTER(?nf = ?total)
} }
}
